    private RenderFragment RenderSecuritySection() => __builder =>
    {
        <section class="settings-section">
            <h4 class="section-title">Security</h4>
            <p class="section-subtitle">Protect your account</p>

            <!-- Change Password -->
            <div class="expandable-panel mb-4">
                <button class="btn btn-outline-secondary w-100 text-start d-flex justify-content-between align-items-center"
                        @onclick="() => _showChangePassword = !_showChangePassword">
                    <span>🔑 Change Password</span>
                    <span>@(_showChangePassword ? "▲" : "▼")</span>
                </button>
                @if (_showChangePassword)
                {
                    <div class="panel-body mt-3">
                        <div class="mb-3">
                            <label class="form-label">Current Password</label>
                            <input type="password" class="form-control" @bind="_currentPassword" />
                        </div>
