{"file_text": "@page "/settings"
@using sv_1e4055962c264e9988fed8ce76db9a7d.Services
@inject ISettingsService SettingsService
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <nav class="settings-sidebar">
        <h5 class="sidebar-title">Settings</h5>
        <ul class="settings-nav">
            @foreach (var section in _sections)
            {
                <li class="settings-nav-item @(section == _activeSection ? "active" : "")"
                    @onclick="() => SetActiveSection(section)">
                    <span class="nav-icon">@GetSectionIcon(section)</span>
                    <span>@section</span>
                </li>
            }
        </ul>
    </nav>

    <div class="settings-content">
        @if (_loading)
        {
            <div class="text-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @switch (_activeSection)
            {
                case "Profile":
                    @RenderProfileSection()
                    break;
                case "Notifications":
                    @RenderNotificationsSection()
                    break;
                case "Security":
                    @RenderSecuritySection()
                    break;
                case "Appearance":
                    @RenderAppearanceSection()
                    break;
            }
        }
    </div>
</div>

@if (_showToast)
{
    <div class="settings-toast @(_toastIsError ? "toast-error" : "toast-success")">
        @_toastMessage
    </div>
}

@if (_showRevokeConfirm)
{
    <div class="modal-backdrop" @onclick="() => _showRevokeConfirm = false"></div>
    <div class="confirm-dialog">
        <h6>Revoke Session</h6>
        <p>Are you sure you want to revoke this session? The device will be signed out immediately.</p>
        <div class="d-flex gap-2 justify-content-end">
            <button class="btn btn-secondary btn-sm" @onclick="() => _showRevokeConfirm = false">Cancel</button>
            <button class="btn btn-danger btn-sm" @onclick="ConfirmRevokeSession">Revoke</button>
        </div>
    </div>
}

@code {
    private readonly string[] _sections = { "Profile", "Notifications", "Security", "Appearance" };
    private string _activeSection = "Profile";
    private bool _loading = true;

    // Toast
    private bool _showToast;
    private string _toastMessage = "";
    private bool _toastIsError;

    // Profile
    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private UserProfile? _savedProfile;

    // Notifications
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<string> _allChannels = MockSettingsService.GetAllChannels();
    private HashSet<string> _mutedChannels = new();

    // Security
    private SecuritySettings? _securitySettings;
    private bool _showChangePassword;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _twoFactorEnabled;
    private bool _showRevokeConfirm;
    private string? _sessionToRevoke;

    // Appearance
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private readonly string[] _themes = { "Light", "Dark", "System" };
    private readonly string[] _fontSizes = { "Small", "Medium", "Large" };
    private readonly string[] _languages = { "English", "Spanish", "French", "German", "Japanese", "Chinese" };

    protected override async Task OnInitializedAsync()
    {
        await LoadSectionData("Profile");
        _loading = false;
    }

    private async Task SetActiveSection(string section)
    {
        if (section == _activeSection) return;
        _activeSection = section;
        _loading = true;
        await LoadSectionData(section);
        _loading = false;
    }

    private async Task LoadSectionData(string section)
    {
        switch (section)
        {
            case "Profile":
                var profile = await SettingsService.GetProfileAsync();
                _savedProfile = profile;
                _displayName = profile.DisplayName;
                _email = profile.Email;
                _avatarUrl = profile.AvatarUrl;
                _bio = profile.Bio;
                break;
            case "Notifications":
                var prefs = await SettingsService.GetNotificationPrefsAsync();
                _emailNotifications = prefs.EmailNotifications;
                _pushNotifications = prefs.PushNotifications;
                _weeklyDigest = prefs.WeeklyDigest;
                _mutedChannels = new HashSet<string>(prefs.MutedChannels);
                break;
            case "Security":
                _securitySettings = await SettingsService.GetSecuritySettingsAsync();
                _twoFactorEnabled = _securitySettings.TwoFactorEnabled;
                _showChangePassword = false;
                _currentPassword = "";
                _newPassword = "";
                _confirmPassword = "";
                break;
            case "Appearance":
                var appearance = await SettingsService.GetAppearanceAsync();
                _theme = appearance.Theme;
                _fontSize = appearance.FontSize;
                _language = appearance.Language;
                _compactMode = appearance.CompactMode;
                break;
        }
    }

    private static string GetSectionIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };

    // Profile actions
    private async Task SaveProfile()
    {
        var profile = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(profile);
        _savedProfile = profile;
        await ShowToast("Profile saved successfully!");
    }

    private void DiscardProfileChanges()
    {
        if (_savedProfile is null) return;
        _displayName = _savedProfile.DisplayName;
        _email = _savedProfile.Email;
        _avatarUrl = _savedProfile.AvatarUrl;
        _bio = _savedProfile.Bio;
    }

    // Notification actions
    private void ToggleChannelMute(string channel)
    {
        if (!_mutedChannels.Remove(channel))
            _mutedChannels.Add(channel);
    }

    private async Task SaveNotifications()
    {
        var prefs = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, _mutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        await ShowToast("Notification preferences saved!");
    }

    // Security actions
    private async Task UpdatePassword()
    {
        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            await ShowToast("Please fill in all password fields.", isError: true);
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            await ShowToast("New passwords do not match.", isError: true);
            return;
        }
        if (_newPassword.Length < 8)
        {
            await ShowToast("Password must be at least 8 characters.", isError: true);
            return;
        }
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
            _showChangePassword = false;
            _securitySettings = await SettingsService.GetSecuritySettingsAsync();
            await ShowToast("Password updated successfully!");
        }
        catch (Exception ex)
        {
            await ShowToast(ex.Message, isError: true);
        }
    }

    private void RequestRevokeSession(string sessionId)
    {
        _sessionToRevoke = sessionId;
        _showRevokeConfirm = true;
    }

    private async Task ConfirmRevokeSession()
    {
        if (_sessionToRevoke is not null)
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke);
            _securitySettings = await SettingsService.GetSecuritySettingsAsync();
            _sessionToRevoke = null;
        }
        _showRevokeConfirm = false;
        await ShowToast("Session revoked.");
    }

    // Appearance actions
    private async Task SaveAppearance()
    {
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        await ShowToast("Appearance settings saved!");
    }

    // Toast helper
    private async Task ShowToast(string message, bool isError = false)
    {
        _toastMessage = message;
        _toastIsError = isError;
        _showToast = true;
        StateHasChanged();
        await Task.Delay(3000);
        _showToast = false;
        StateHasChanged();
    }

    // Render fragments
    private RenderFragment RenderProfileSection() => __builder =>
    {
        <section class="settings-section">
            <h4 class="section-title">Profile</h4>
            <p class="section-subtitle">Manage your personal information</p>

            <div class="avatar-area mb-4">
                <img src="@_avatarUrl" alt="Avatar" class="avatar-preview" />
                <span class="avatar-url text-muted">@_avatarUrl</span>
            </div>

            <div class="mb-3">
                <label class="form-label">Display Name</label>
                <input type="text" class="form-control" @bind="_displayName" />
            </div>
            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="_email" />
            </div>
            <div class="mb-3">
                <label class="form-label">Bio</label>
                <textarea class="form-control" rows="3" @bind="_bio"></textarea>
            </div>

            <div class="d-flex gap-2">
                <button class="btn btn-primary" @onclick="SaveProfile">Save Changes</button>
                <button class="btn btn-outline-secondary" @onclick="DiscardProfileChanges">Discard Changes</button>
            </div>
        </section>
    };

    private RenderFragment RenderNotificationsSection() => __builder =>
    {
        <section class="settings-section">
            <h4 class="section-title">Notifications</h4>
            <p class="section-subtitle">Choose how you want to be notified</p>

            <div class="toggle-group">
                <div class="toggle-row">
                    <div>
                        <strong>Email Notifications</strong>
                        <div class="text-muted small">Receive updates via email</div>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch" @bind="_emailNotifications" />
                    </div>
                </div>
                <div class="toggle-row">
                    <div>
                        <strong>Push Notifications</strong>
                        <div class="text-muted small">Receive push notifications on your devices</div>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch" @bind="_pushNotifications" />
                    </div>
                </div>
                <div class="toggle-row">
                    <div>
                        <strong>Weekly Digest</strong>
                        <div class="text-muted small">Get a summary of activity each week</div>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch" @bind="_weeklyDigest" />
                    </div>
                </div>
            </div>

            <h6 class="mt-4 mb-3">Muted Channels</h6>
            <div class="channel-list">
                @foreach (var channel in _allChannels)
                {
                    <div class="form-check">
                        <input class="form-check-input darker-border-checkbox" type="checkbox"
                               id="@($"ch-{channel}")"
                               checked="@_mutedChannels.Contains(channel)"
                               @onchange="() => ToggleChannelMute(channel)" />
                        <label class="form-check-label" for="@($"ch-{channel}")">
                            #@channel @(_mutedChannels.Contains(channel) ? "(muted)" : "")
                        </label>
                    </div>
                }
            </div>

            <button class="btn btn-primary mt-4" @onclick="SaveNotifications">Save Preferences</button>
        </section>
    };

    private RenderFragment RenderSecuritySection() => __builder =>
    {
        <section class="settings-section">
            <h4 class="section-title">Security</h4>
            <p class="section-subtitle">Protect your account</p>

            <!-- Change Password -->
            <div class="expandable-panel mb-4">
                <button class="btn btn-outline-secondary w-100 text-start d-flex justify-content-between align-items-center"
                        @onclick="() => _showChangePassword = !_showChangePassword">
                    <span>🔑 Change Password</span>
                    <span>@(_showChangePassword ? "▲" : "▼")</span>
                </button>
                @if (_showChangePassword)
                {
                    <div class="panel-body mt-3">
                        <div class="mb-3">
                            <label class="form-label">Current Password</label>
                            <input type="password" class="form-control" @bind="_currentPassword" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">New Password</label>
                            <input type="password" class="form-control" @bind="_newPassword" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">Confirm New Password</label>
                            <input type="password" class="form-control" @bind="_confirmPassword" />
                        </div>
                        <button class="btn btn-primary" @onclick="UpdatePassword">Update Password</button>
                    </div>
                }
            </div>

            @if (_securitySettings?.LastPasswordChange is not null)
            {
                <p class="text-muted small mb-4">
                    Last password change: @_securitySettings.LastPasswordChange.Value.ToString("MMMM d, yyyy")
                </p>
            }

            <!-- Two-Factor Authentication -->
            <div class="toggle-row mb-4">
                <div>
                    <strong>Two-Factor Authentication</strong>
                    <div class="small">
                        <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary") me-1">
                            @(_twoFactorEnabled ? "Enabled" : "Disabled")
                        </span>
                        Add an extra layer of security
                    </div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch" @bind="_twoFactorEnabled" />
                </div>
            </div>

            <!-- Active Sessions -->
            <h6 class="mt-4 mb-3">Active Sessions</h6>
            @if (_securitySettings?.Sessions is { Count: > 0 })
            {
                <div class="table-responsive">
                    <table class="table table-hover">
                        <thead>
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var session in _securitySettings.Sessions)
                            {
                                var isCurrent = session.Id == _securitySettings.Sessions[0].Id;
                                <tr>
                                    <td>
                                        @session.Device
                                        @if (isCurrent)
                                        {
                                            <span class="badge bg-primary ms-1">Current</span>
                                        }
                                    </td>
                                    <td>@session.Location</td>
                                    <td>@FormatLastActive(session.LastActive)</td>
                                    <td>
                                        @if (!isCurrent)
                                        {
                                            <button class="btn btn-outline-danger btn-sm"
                                                    @onclick="() => RequestRevokeSession(session.Id)">
                                                Revoke
                                            </button>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            }
            else
            {
                <p class="text-muted">No active sessions found.</p>
            }
        </section>
    };

    private RenderFragment RenderAppearanceSection() => __builder =>
    {
        <section class="settings-section">
            <h4 class="section-title">Appearance</h4>
            <p class="section-subtitle">Customize how the app looks</p>

            <!-- Theme -->
            <div class="mb-4">
                <label class="form-label fw-semibold">Theme</label>
                <div class="d-flex gap-3">
                    @foreach (var t in _themes)
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="theme" id="@($"theme-{t}")"
                                   value="@t" checked="@(_theme == t)"
                                   @onchange="() => _theme = t" />
                            <label class="form-check-label" for="@($"theme-{t}")">@t</label>
                        </div>
                    }
                </div>
            </div>

            <!-- Font Size -->
            <div class="mb-4">
                <label class="form-label fw-semibold">Font Size</label>
                <div class="d-flex gap-3">
                    @foreach (var fs in _fontSizes)
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="fontSize" id="@($"fs-{fs}")"
                                   value="@fs" checked="@(_fontSize == fs)"
                                   @onchange="() => _fontSize = fs" />
                            <label class="form-check-label" for="@($"fs-{fs}")">@fs</label>
                        </div>
                    }
                </div>
            </div>

            <!-- Language -->
            <div class="mb-4">
                <label class="form-label fw-semibold">Language</label>
                <select class="form-select" style="max-width: 300px;" @bind="_language">
                    @foreach (var lang in _languages)
                    {
                        <option value="@lang">@lang</option>
                    }
                </select>
            </div>

            <!-- Compact Mode -->
            <div class="toggle-row mb-4">
                <div>
                    <strong>Compact Mode</strong>
                    <div class="text-muted small">Reduce spacing and padding throughout the UI</div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch" @bind="_compactMode" />
                </div>
            </div>

            <!-- Live Preview -->
            <div class="mb-4">
                <label class="form-label fw-semibold">Preview</label>
                <div class="appearance-preview @GetPreviewClasses()">
                    <div class="preview-header">
                        <strong>Sample Card</strong>
                    </div>
                    <div class="preview-body">
                        <p>This is a preview of how your selected appearance settings will look.</p>
                        <div class="d-flex gap-2">
                            <button class="btn btn-primary btn-sm">Primary</button>
                            <button class="btn btn-outline-secondary btn-sm">Secondary</button>
                        </div>
                    </div>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="SaveAppearance">Save</button>
        </section>
    };

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        classes.Add(_theme switch { "Dark" => "preview-dark", "System" => "preview-system", _ => "preview-light" });
        classes.Add(_fontSize switch { "Small" => "preview-font-sm", "Large" => "preview-font-lg", _ => "preview-font-md" });
        if (_compactMode) classes.Add("preview-compact");
        return string.Join(" ", classes);
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}
